class Solution:
    def minimumWhiteTiles(self, floor, numCarpets, carpetLen):
        n = len(floor)
        from functools import lru_cache

        @lru_cache(maxsize=None)
        def rec(i, c):
            if i >= n:
                return 0
            skip = (1 if floor[i] == '1' else 0) + rec(i + 1, c)
            if c > 0:
                cover = rec(min(n, i + carpetLen), c - 1)
                return min(skip, cover)
            return skip

        result = rec(0, numCarpets)
        rec.cache_clear()
        return result

