class Solution:
    def minimumWhiteTiles(self, floor, numCarpets, carpetLen):
        n = len(floor)
        prev = [0] * (n + 1)
        for i in range(n - 1, -1, -1):
            prev[i] = prev[i + 1] + (1 if floor[i] == '1' else 0)
        dp = [[0] * (numCarpets + 1) for _ in range(n + 1)]
        for i in range(n + 1):
            dp[i][0] = prev[i]
        for c in range(1, numCarpets + 1):
            dp[n][c] = 0
        for i in range(n - 1, -1, -1):
            for c in range(1, numCarpets + 1):
                skip = (1 if floor[i] == '1' else 0) + dp[i + 1][c]
                cover = dp[min(n, i + carpetLen)][c - 1]
                dp[i][c] = min(skip, cover)
        return dp[0][numCarpets]

