var minimumWhiteTiles = function(floor, numCarpets, carpetLen) {
    const n = floor.length;
    const dp = Array.from({ length: n + 1 }, () => new Array(numCarpets + 1).fill(0));
    for (let i = n - 1; i >= 0; i--) {
        dp[i][0] = dp[i + 1][0] + (floor[i] === '1' ? 1 : 0);
    }
    for (let i = n - 1; i >= 0; i--) {
        for (let c = 1; c <= numCarpets; c++) {
            const skip = (floor[i] === '1' ? 1 : 0) + dp[i + 1][c];
            const cover = dp[Math.min(n, i + carpetLen)][c - 1];
            dp[i][c] = Math.min(skip, cover);
        }
    }
    return dp[0][numCarpets];
};
